1515   else if (!Cmp.isSigned() &&
1516            match(&Cmp, m_c_ICmp(Pred, m_NUWTrunc(m_Value(X)),
1517                                 m_OneUse(m_ZExt(m_Value(Y)))))) {
1518     // Can fold trunc nuw + zext for unsigned and equality predicates.
1519   }
