220 bool InstCombinerImpl::isDesirableIntType(unsigned BitWidth) const {
221   switch (BitWidth) {
222   case 8:
223   case 16:
224   case 32:
225     return true;
226   default:
227     return DL.isLegalInteger(BitWidth);
228   }
229 }
